import { useState, useEffect, useCallback, useRef } from "react";
import { createGsdClient } from "@/services/gsd-client";
import { useProjectStore } from "@/stores/project-store";
import { deriveCostData } from "@/lib/derive-cost-data";
import type { MilestoneInfo, CostData } from "@/lib/types";

const client = createGsdClient();

interface UseMilestoneDataResult {
  milestones: MilestoneInfo[];
  costData: CostData;
  isLoading: boolean;
  error: string | null;
  refetch: () => void;
}

const emptyCostData: CostData = {
  totalCost: 0,
  budgetCeiling: null,
  byPhase: [],
  byModel: [],
  bySlice: [],
};

/**
 * Hook that fetches parsed milestone data when the active project changes.
 *
 * Subscribes to `useProjectStore.activeProject`. When it changes to a
 * non-null value, calls `parseProjectMilestones` via the GSD client
 * and derives cost data from the result.
 *
 * Returns `{ milestones, costData, isLoading, error, refetch }`.
 */
export function useMilestoneData(): UseMilestoneDataResult {
  const activeProject = useProjectStore((s) => s.activeProject);
  const [milestones, setMilestones] = useState<MilestoneInfo[]>([]);
  const [costData, setCostData] = useState<CostData>(emptyCostData);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Track the fetch generation to discard stale responses
  const fetchGenRef = useRef(0);

  const fetchData = useCallback(
    async (projectPath: string) => {
      const gen = ++fetchGenRef.current;
      setIsLoading(true);
      setError(null);

      try {
        const data = await client.parseProjectMilestones(projectPath);

        // Discard if a newer fetch has been initiated
        if (gen !== fetchGenRef.current) return;

        setMilestones(data);
        setCostData(deriveCostData(data));
      } catch (err) {
        if (gen !== fetchGenRef.current) return;

        const message = err instanceof Error ? err.message : String(err);
        setError(message);
        setMilestones([]);
        setCostData(emptyCostData);
      } finally {
        if (gen === fetchGenRef.current) {
          setIsLoading(false);
        }
      }
    },
    [],
  );

  // Fetch when activeProject changes
  useEffect(() => {
    if (!activeProject) {
      setMilestones([]);
      setCostData(emptyCostData);
      setError(null);
      setIsLoading(false);
      return;
    }

    fetchData(activeProject.path);
  }, [activeProject, fetchData]);

  const refetch = useCallback(() => {
    if (activeProject) {
      fetchData(activeProject.path);
    }
  }, [activeProject, fetchData]);

  return { milestones, costData, isLoading, error, refetch };
}

import { describe, expect, it, vi } from "vitest";
import { renderWithProviders, screen } from "@/test/test-utils";
import { ChatPage } from "@/pages/chat-page";
import { ProjectsPage } from "@/pages/projects-page";
import { MilestonesPage } from "@/pages/milestones-page";
import { TimelinePage } from "@/pages/timeline-page";
import { CostsPage } from "@/pages/costs-page";
import { SettingsPage } from "@/pages/settings-page";
import { HelpPage } from "@/pages/help-page";

vi.mock("@tauri-apps/plugin-dialog", () => ({
  open: vi.fn(),
}));

vi.mock("@/services/gsd-client", () => ({
  createGsdClient: () => ({
    startSession: vi.fn(), stopSession: vi.fn(), sendCommand: vi.fn(),
    queryState: vi.fn(), listProjects: vi.fn(), startFileWatcher: vi.fn(),
    stopFileWatcher: vi.fn(),
    getSavedProjects: vi.fn().mockResolvedValue([]),
    addProject: vi.fn(), removeProject: vi.fn(),
    onGsdEvent: vi.fn().mockResolvedValue(vi.fn()),
    onProcessExit: vi.fn().mockResolvedValue(vi.fn()),
    onProcessError: vi.fn().mockResolvedValue(vi.fn()),
    onFileChanged: vi.fn().mockResolvedValue(vi.fn()),
  }),
}));

// The pages test checks for synchronous content. The ProjectGallery now auto-loads
// on mount via useEffect, which briefly shows loading state. The mock getSavedProjects
// resolves immediately so the empty state renders.

interface PageDef {
  name: string;
  Component: React.ComponentType;
  uniqueText: string;
  hasMockSections?: boolean;
  sections?: string[];
}

const pages: PageDef[] = [
  {
    name: "Chat",
    Component: ChatPage,
    uniqueText: "Start a conversation",
    hasMockSections: false,
  },
  {
    name: "Projects",
    Component: ProjectsPage,
    uniqueText: "No projects",
    hasMockSections: false,
  },
  {
    name: "Milestones",
    Component: MilestonesPage,
    uniqueText: "M001",
    hasMockSections: false,
  },
  {
    name: "Timeline",
    Component: TimelinePage,
    uniqueText: "Rust process manager",
    hasMockSections: false,
  },
  {
    name: "Costs",
    Component: CostsPage,
    uniqueText: "Cost by Phase",
    hasMockSections: false,
  },
  {
    name: "Settings",
    Component: SettingsPage,
    uniqueText: "Token Profile",
    hasMockSections: false,
  },
  {
    name: "Help",
    Component: HelpPage,
    uniqueText: "Getting Started",
    hasMockSections: true,
    sections: ["Getting Started", "Keyboard Shortcuts"],
  },
];

describe("Page components", () => {
  for (const { name, Component } of pages) {
    it(`${name}Page renders a heading with "${name}"`, () => {
      renderWithProviders(<Component />);
      expect(
        screen.getByRole("heading", { level: 1, name: new RegExp(name, "i") }),
      ).toBeInTheDocument();
    });
  }

  for (const { name, Component } of pages) {
    it(`${name}Page renders a page icon`, () => {
      renderWithProviders(<Component />);
      expect(screen.getByTestId("page-icon")).toBeInTheDocument();
    });
  }

  for (const { name, Component, uniqueText } of pages) {
    it(`${name}Page renders page-specific content ("${uniqueText}")`, async () => {
      renderWithProviders(<Component />);
      expect(await screen.findByText(new RegExp(uniqueText, "i"))).toBeInTheDocument();
    });
  }

  const pagesWithMockSections = pages.filter((p) => p.hasMockSections && p.sections);
  for (const { name, Component, sections } of pagesWithMockSections) {
    it(`${name}Page renders mock data sections`, () => {
      renderWithProviders(<Component />);
      const mockSections = screen.getAllByTestId("mock-section");
      expect(mockSections.length).toBeGreaterThanOrEqual(2);
      for (const sectionTitle of sections!) {
        const matches = screen.getAllByText(new RegExp(sectionTitle, "i"));
        expect(matches.length).toBeGreaterThanOrEqual(1);
      }
    });
  }
});

